#include <bits/stdc++.h>
using namespace std;
struct Node{
    int to,val;
};
int n,m,l,r,c[20004];
vector<Node> g[20004];
bool dfs(int x,int y){
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i].val>y){
            if(!c[g[x][i].to]){
                c[g[x][i].to]=3-c[x];
                if(!dfs(g[x][i].to,y))
                    return false;
            }
            else if(c[g[x][i].to]==c[x])
                return false;
        }
    return true;
}
bool check(int x){
    memset(c,0,sizeof(c));
    for(int i=1;i<=n;i++)
        if(!c[i]){
            c[i]=1;
            if(!dfs(i,x))
                return false;
        }
    return true;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        g[a].push_back({b,c});
        g[b].push_back({a,c});
        r=max(r,c);
    }
    while(l<r){
        int mid=(l+r)/2;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    cout<<r;
    return 0;
}
